spec.expr:
1000 * max by (runtime, benchmark, testid) (
  k6_http_req_duration_p99{
    runtime=~"$runtime",
    benchmark=~"$benchmark",
    testid=~"$testid",
    phase="measurement"
  }
)

1000 * max by (runtime, benchmark, testid) (
  k6_http_req_waiting_p99{
    runtime=~"$runtime",
    benchmark=~"$benchmark",
    testid=~"$testid",
    phase="measurement",
    benchmark=~"read|write"
  }
)

100 * avg by (runtime, benchmark, testid) (
  k6_http_req_failed_rate{
    runtime=~"$runtime",
    benchmark=~"$benchmark",
    testid=~"$testid",
    phase="measurement"
  }
)

sum by (runtime, benchmark, testid) (
  increase(k6_http_reqs_total{
    runtime=~"$runtime",
    benchmark=~"$benchmark",
    testid=~"$testid",
    phase="measurement"
  }[$__range])
)

max by (runtime, benchmark, testid) (
  k6_vus{
    runtime=~"$runtime",
    benchmark=~"$benchmark",
    testid=~"$testid",
    phase="measurement"
  }
)

sum by (runtime, benchmark, testid) (
  rate(k6_http_reqs_total{
    runtime=~"$runtime",
    benchmark=~"$benchmark",
    testid=~"$testid",
    phase="measurement",
    benchmark=~"ping|read|write"
  }[$__rate_interval])
)

avg_over_time((
  sum by (runtime, benchmark, testid) (
    rate(k6_http_reqs_total{
    runtime=~"$runtime",
    benchmark=~"$benchmark",
    testid=~"$testid",
    phase="measurement",
    benchmark=~"ping|read|write"
  }[30s])
  )
)[$__range:$__interval])

1000 * max by (runtime, benchmark, testid) (
  k6_http_req_duration_p99{
    runtime=~"$runtime",
